static int ReadAsciiWord(string input, ref int index)
    {
        var start = index;
        var c = input[index];
        if (IsAsciiDigit(c))
        {
            index++;
            while (index < input.Length && IsAsciiDigit(input[index]))
            {
                index++;
            }

            while (index < input.Length && IsAsciiLower(input[index]))
            {
                index++;
            }

            return index - start;
        }

        if (IsAsciiLower(c))
        {
            index++;
            while (index < input.Length && IsAsciiLower(input[index]))
            {
                index++;
            }

            return index - start;
        }

        if (!IsAsciiUpper(c))
        {
            return 0;
        }

        var upperStart = index;
        index++;
        while (index < input.Length && IsAsciiUpper(input[index]))
        {
            index++;
        }

        if (index < input.Length && IsAsciiLower(input[index]))
        {
            if (index - upperStart > 1)
            {
                index--;
                return index - start;
            }

            index++;
            while (index < input.Length && IsAsciiLower(input[index]))
            {
                index++;
            }
        }

        return index - start;
    }

class EnricherStack : IEnumerable<ILogEventEnricher>
{
    readonly EnricherStack? _under;
    readonly ILogEventEnricher? _top;

    EnricherStack()
    {
    }

    EnricherStack(EnricherStack under, ILogEventEnricher top)
    {
        _under = Guard.AgainstNull(under);
        Count = under.Count + 1;
        _top = top;
    }

    public Enumerator GetEnumerator() => new(this);

    IEnumerator<ILogEventEnricher> IEnumerable<ILogEventEnricher>.GetEnumerator() => new Enumerator(this);

    IEnumerator IEnumerable.GetEnumerator() => new Enumerator(this);

    public int Count { get; }

    public static EnricherStack Empty { get; } = new();

    public bool IsEmpty => _under == null;

    public EnricherStack Push(ILogEventEnricher t) => new(this, t);

    public ILogEventEnricher Top => _top!;

    internal struct Enumerator : IEnumerator<ILogEventEnricher>
    {
        readonly EnricherStack _stack;
        EnricherStack _top;
        ILogEventEnricher? _current;

        public Enumerator(EnricherStack stack)
        {
            _stack = stack;
            _top = stack;
            _current = null;
        }

        public bool MoveNext()
        {
            if (_top.IsEmpty)
                return false;
            _current = _top.Top;
            _top = _top._under!;
            return true;
        }

        public void Reset()
        {
            _top = _stack;
            _current = null;
        }

        public ILogEventEnricher Current => _current!;

        object IEnumerator.Current => _current!;

        public void Dispose()
        {
        }
    }
}

